// RecyclableMemoryStream (Microsoft.IO.RecyclableMemoryStream)
private static readonly RecyclableMemoryStreamManager _manager = new();

public async Task<byte[]> SerializeAsync<T>(T data, CancellationToken ct)
{
    using var stream = _manager.GetStream();  // pool-backed, tự trả về khi Dispose
    await JsonSerializer.SerializeAsync(stream, data, AppJsonContext.Default.GetTypeInfo(typeof(T))!, ct);
    return stream.ToArray(); // chỉ alloc tại đây
}

// Hoặc dùng ArrayPool để tránh alloc hoàn toàn
public async Task SerializeToWriterAsync<T>(T data, PipeWriter writer, CancellationToken ct)
{
    await JsonSerializer.SerializeAsync(writer.AsStream(), data, ct: ct);
    await writer.FlushAsync(ct);
}

// ObjectPool<StringBuilder>
private static readonly ObjectPool<StringBuilder> _sbPool =
    new DefaultObjectPoolProvider().CreateStringBuilderPool();

public string BuildComplexMessage(Order order)
{
    var sb = _sbPool.Get();
    try
    {
        sb.Append("Order #").Append(order.Id).Append(" - ");
        sb.Append(order.Status).Append(" - ").Append(order.Total.ToString("C"));
        return sb.ToString();
    }
    finally { _sbPool.Return(sb); } // PHẢI trong finally
}
